class Solution {
public:
    int isPrefixOfWord(string sentence, string searchWord) {
        int index = 1, wordLen = 0;
        for (char c : sentence) {
            if (c == ' ') {
                if (sentence.substr(wordLen, searchWord.length()) == searchWord) {
                    return index;
                }
                index++;
                wordLen = 0;
            } else {
                wordLen++;
            }
        }
        if (sentence.substr(wordLen, searchWord.length()) == searchWord) {
            return index;
        }
        return -1;
    }
};
```

